package com.example.mod;

import net.minecraft.core.Registry;
import net.minecraft.world.item.CreativeModeTab;
import net.minecraft.world.item.Item;
import net.minecraft.world.item.ItemStack;
import net.minecraft.world.level.block.Block;
import net.minecraft.world.level.block.Blocks;
import net.minecraftforge.event.BuildCreativeTabEvent;
import net.minecraftforge.event.RegisterRecipesEvent;
import net.minecraftforge.fml.javafmlmod.FMLJavaModLoadingContext;
import net.minecraftforge.registries.DeferredRegister;
import net.minecraftforge.registries.ForgeRegistries;

public class Mod {

    public static final DeferredRegister<Item> ITEMS = DeferredRegister.create(ForgeRegistries.ITEMS, "veriditas_mod");
    public static final DeferredRegister<Block> BLOCKS = DeferredRegister.create(ForgeRegistries.BLOCKS, "veriditas_mod");

    // Furniture Block
    public static final RegistryObject<Block> VERIDITAS_TABLE = BLOCKS.register("veriditas_table", () -> new VeriditasTable());

    // Furniture Item
    public static final RegistryObject<Item> VERIDITAS_TABLE_ITEM = ITEMS.register("veriditas_table_item", () -> new VeriditasTableItem());

    // Crafting Recipe
    public static class VeriditasTableRecipe extends ShapedRecipe {
        public VeriditasTableRecipe() {
            super(new ShapelessRecipeSerializer<>(VeriditasTableItem::new).setRegistryName("veriditas_table_recipe"),
                    new ItemStack(VERIDITAS_TABLE.get()),
                    Arrays.asList(
                            new Ingredient(Items.OAK_PLANKS, 4),
                            new Ingredient(Items.WOODEN_SAW)
                    )
            );
        }
    }

    public static void init() {
        ITEMS.register();
        BLOCKS.register();

        MinecraftForge.EVENT_BUS.addListener(BuildCreativeTabEvent.class, event -> {
            event.getTabs().add(new CreativeModeTab("veriditas_tab") {
                @Override
                public ItemStack makeIcon() {
                    return new ItemStack(VERIDITAS_TABLE.get());
                }
            });
        });

        MinecraftForge.EVENT_BUS.addListener(RegisterRecipesEvent.class, event -> {
            event.addShaped(new VeriditasTableRecipe());
        });
    }

    public static void main(String[] args) {
        FMLJavaModLoadingContext.get().getModEventBus().addListener(Mod::init);
    }
}
